const { event, data } = context;
if (event !== 'sla.breached') return;
const cfg = cliaas.config;
const priorities = ['low','normal','high','urgent'];
const idx = priorities.indexOf(data.priority || 'normal');
const newPriority = priorities[Math.min(idx+1, priorities.length-1)];
cliaas.log.info(`Escalating ticket ${data.ticketId} from ${data.priority} to ${newPriority}`);
